require"UI.UIBase"require"UI.UIBlock"require"GameUtility"UI_GameStop=UIBase:Inherit()local a=GameUtility.EMJ_Mode;function UI_GameStop:OnCreate()UI_GameStop.Inst=self;self.enable=false;self.blackbg=self.transform:Find('blackbg')self.blackbg_anim_alpha=self.blackbg:GetComponent(typeof(anim_alpha))self.img_pause=self.transform:Find('Image'):GetComponent(typeof(UnityEngine.CanvasGroup))self.loop_timer=TimerMgr:Init()end;function UI_GameStop:OnShow(b)if self.enable then return end;self.transform.gameObject:SetActive(true)self.enable=true;if DesktopMgr.Inst.mode==a.play then self.blackbg.gameObject:SetActive(true)self.blackbg:GetComponent(typeof(UnityEngine.CanvasGroup)).alpha=0;self.blackbg_anim_alpha:Alpha_In()else self.blackbg.gameObject:SetActive(false)end;self:AnimAlphaIn(self.transform,{x=0,y=0},0.2,nil,function()b()end)self:PingPong(1)end;function UI_GameStop:PingPong(c)if not self.transform.gameObject.activeInHierarchy then return end;local d=DG.Tweening.Ease.InCubic;local e=1;if c==1 then d=DG.Tweening.Ease.OutCubic;e=0.6 end;local f=self.img_pause:DOFade(c,0.8):SetEase(d)f:OnComplete(function()self:PingPong(e)end)end;function UI_GameStop:OnClose(b)if not self.enable then return end;self.enable=false;self.transform.gameObject:SetActive(false)b()end;return UI_GameStop